import 'package:flutter/material.dart';import 'app_colors.dart';import 'app_spacing.dart';import 'app_typography.dart';class DsInputField extends StatefulWidget {  final String? labelText;  final String? hintText;  final TextEditingController? controller;  final bool obscureText;  final TextInputType? keyboardType;  final ValueChanged<String>? onChanged;  final Widget? suffixIcon;  final bool readOnly;  final VoidCallback? onTap;  const DsInputField({    super.key,    this.labelText,    this.hintText,    this.controller,    this.obscureText = false,    this.keyboardType,    this.onChanged,    this.suffixIcon,    this.readOnly = false,    this.onTap,  });  @override  State<DsInputField> createState() => _DsInputFieldState();}@overrideclass _DsInputFieldState extends State<DsInputField> {  late FocusNode _focusNode;  bool _isFocused = false;  @override  void initState() {    super.initState();    _focusNode = FocusNode();    _focusNode.addListener(_onFocusChange);  }  @override  void dispose() {    _focusNode.removeListener(_onFocusChange);    _focusNode.dispose();    super.dispose();  }  void _onFocusChange() {    setState(() {      _isFocused = _focusNode.hasFocus;    });  }  @override  Widget build(BuildContext context) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        if (widget.labelText != null)          Padding(            padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall / 2),            child: Text(              widget.labelText!,              style: AppTypography.body.copyWith(color: AppColors.textSecondary),            ),          ),        GestureDetector(          onTap: widget.onTap ?? () => _focusNode.requestFocus(),          child: AbsorbPointer(            absorbing: widget.onTap != null,            child: AnimatedContainer(              duration: const Duration(milliseconds: 200),              curve: Curves.easeOut,              decoration: BoxDecoration(                color: AppColors.surface,                borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                border: Border.all(                  color: _isFocused ? AppColors.primary : AppColors.inputBorder,                  width: _isFocused ? 1.5 : 1,                ),                boxShadow: _isFocused                  ? [                      BoxShadow(                        color: AppColors.primary.withOpacity(0.3),                        blurRadius: 8,                        spreadRadius: 1,                      ),                    ]                  : [],              ),              child: TextField(                controller: widget.controller,                obscureText: widget.obscureText,                keyboardType: widget.keyboardType,                onChanged: widget.onChanged,                readOnly: widget.readOnly,                focusNode: _focusNode,                style: AppTypography.inputField,                cursorColor: AppColors.primary,                decoration: InputDecoration(                  hintText: widget.hintText,                  hintStyle: AppTypography.inputField.copyWith(color: AppColors.inputPlaceholder),                  contentPadding: AppSpacing.inputPadding,                  isDense: true,                  border: InputBorder.none,                  suffixIcon: widget.suffixIcon,                ),              ),            ),          ),        ),      ],    );  }}